"""
Rosalind Problem 6: Counting Point Mutations
https://rosalind.info/problems/hamm/

Given two DNA strings of equal length, compute the Hamming distance:
the number of positions at which the corresponding symbols differ.
"""

s = ""
t = ""

count = 0
for harf1, harf2 in zip(s, t):
    if harf1 != harf2:
        count += 1

print(count)
